    {
        _currentPage = 1;
        await SearchAsync();
    }

    // ── Pagination ──
    private async Task GoToPageAsync(int page)
    {
        if (page < 1 || page > TotalPages || page == _currentPage)
            return;

        _currentPage = page;
        await SearchAsync();
    }

