<div class="row">
    @* ── Left sidebar: filters ── *@
    <aside class="col-md-3">
        <div class="card mb-3">
            <div class="card-header fw-bold">Filters</div>
            <div class="card-body">
                @* Categories *@
                <h6>Category</h6>
                @if (_categories is null)
                {
                    <p class="text-muted small">Loading…</p>
                }
                else
                {
                    @foreach (var cat in _categories)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="checkbox" id="@($"cat-{cat}")"
                                   checked="@_selectedCategories.Contains(cat)"
                                   @onchange="e => ToggleCategory(cat, (bool)e.Value!)" />
                            <label class="form-check-label" for="@($"cat-{cat}")">@cat</label>
                        </div>
                    }
                }

                <hr />

                @* Price range *@
                <h6>Price Range</h6>
                <div class="mb-2">
                    <label class="form-label small mb-0">Min</label>
                    <input type="number" class="form-control form-control-sm" min="0" step="0.01"
                           @bind="_minPrice" placeholder="0.00" />
                </div>
                <div class="mb-2">
                    <label class="form-label small mb-0">Max</label>
                    <input type="number" class="form-control form-control-sm" min="0" step="0.01"
                           @bind="_maxPrice" placeholder="Any" />
                </div>

                <hr />

                @* In stock only *@
                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="inStockOnly"
                           @bind="_inStockOnly" />
                    <label class="form-check-label" for="inStockOnly">In Stock Only</label>
                </div>

                <div class="d-grid gap-2">
                    <button class="btn btn-primary btn-sm" @onclick="ApplyFiltersAsync">Apply Filters</button>
                    <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFiltersAsync">Clear Filters</button>
                </div>
            </div>
        </div>
    </aside>

    @* ── Main content area ── *@
    <section class="col-md-9">
        @* Toolbar *@
        <div class="d-flex justify-content-between align-items-center mb-3">
            <div>
                <label class="form-label small mb-0 me-1" for="sortSelect">Sort by</label>
                <select id="sortSelect" class="form-select form-select-sm d-inline-block w-auto"
                        @bind="_sortBy" @bind:after="OnSortChangedAsync">
                    <option value="price_asc">Price: Low to High</option>
                    <option value="price_desc">Price: High to Low</option>
                    <option value="name_asc">Name: A–Z</option>
                    <option value="rating_desc">Rating: Highest</option>
                </select>
            </div>
            @if (_result is not null && _result.Items.Count > 0)
            {
                <span class="text-muted small">
                    Showing @((_result.Page - 1) * _result.PageSize + 1)–@Math.Min(_result.Page * _result.PageSize, _result.TotalCount)
                    of @_result.TotalCount products
                </span>
            }
        </div>

        @* Product grid *@
        @if (_loading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading…</span>
                </div>
            </div>
        }
        else if (_result is null || _result.Items.Count == 0)
        {
            <div class="alert alert-info text-center" role="alert">
                No products found. Try adjusting your filters.
            </div>
        }
        else
        {
            <div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3">
                @foreach (var product in _result.Items)
                {
                    <div class="col">
                        <ProductCard Product="product"
                                     OnProductSelected="HandleProductSelected"
                                     OnAddToCart="HandleAddToCart" />
                    </div>
                }
            </div>

            @* Pagination *@
            @if (TotalPages > 1)
            {
                <nav class="mt-4" aria-label="Product pagination">
                    <ul class="pagination justify-content-center">
                        <li class="page-item @(_currentPage == 1 ? "disabled" : "")">
                            <button class="page-link" @onclick="() => GoToPageAsync(_currentPage - 1)">Previous</button>
                        </li>
                        @foreach (var p in PageNumbers)
                        {
                            <li class="page-item @(p == _currentPage ? "active" : "")">
                                <button class="page-link" @onclick="() => GoToPageAsync(p)">@p</button>
                            </li>
                        }
                        <li class="page-item @(_currentPage == TotalPages ? "disabled" : "")">
                            <button class="page-link" @onclick="() => GoToPageAsync(_currentPage + 1)">Next</button>
                        </li>
                    </ul>
                </nav>
            }
        }
    </section>
</div>

