{"file_text": "@page "/catalog"
@rendermode InteractiveServer
@using sv_54dd8c2974da4827bdfefdb9af45622e.Services
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

@if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @_errorMessage
        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="RetryAsync">Retry</button>
    </div>
}

<div class="row">
    @* ── Left sidebar: filters ── *@
    <aside class="col-md-3">
        <div class="card mb-3">
            <div class="card-header fw-bold">Filters</div>
            <div class="card-body">
                @* Categories *@
                <h6>Category</h6>
                @if (_categories is null)
                {
                    <p class="text-muted small">Loading…</p>
                }
                else
                {
                    @foreach (var cat in _categories)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="checkbox" id="@($"cat-{cat}")"
                                   checked="@_selectedCategories.Contains(cat)"
                                   @onchange="e => ToggleCategory(cat, (bool)e.Value!)" />
                            <label class="form-check-label" for="@($"cat-{cat}")">@cat</label>
                        </div>
                    }
                }

                <hr />

                @* Price range *@
                <h6>Price Range</h6>
                <div class="mb-2">
                    <label class="form-label small mb-0">Min</label>
                    <input type="number" class="form-control form-control-sm" min="0" step="0.01"
                           @bind="_minPrice" placeholder="0.00" />
                </div>
                <div class="mb-2">
                    <label class="form-label small mb-0">Max</label>
                    <input type="number" class="form-control form-control-sm" min="0" step="0.01"
                           @bind="_maxPrice" placeholder="Any" />
                </div>

                <hr />

                @* In stock only *@
                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="inStockOnly"
                           @bind="_inStockOnly" />
                    <label class="form-check-label" for="inStockOnly">In Stock Only</label>
                </div>

                <div class="d-grid gap-2">
                    <button class="btn btn-primary btn-sm" @onclick="ApplyFiltersAsync">Apply Filters</button>
                    <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFiltersAsync">Clear Filters</button>
                </div>
            </div>
        </div>
    </aside>

    @* ── Main content area ── *@
    <section class="col-md-9">
        @* Toolbar *@
        <div class="d-flex justify-content-between align-items-center mb-3">
            <div>
                <label class="form-label small mb-0 me-1" for="sortSelect">Sort by</label>
                <select id="sortSelect" class="form-select form-select-sm d-inline-block w-auto"
                        @bind="_sortBy" @bind:after="OnSortChangedAsync">
                    <option value="price_asc">Price: Low to High</option>
                    <option value="price_desc">Price: High to Low</option>
                    <option value="name_asc">Name: A–Z</option>
                    <option value="rating_desc">Rating: Highest</option>
                </select>
            </div>
            @if (_result is not null && _result.Items.Count > 0)
            {
                <span class="text-muted small">
                    Showing @((_result.Page - 1) * _result.PageSize + 1)–@Math.Min(_result.Page * _result.PageSize, _result.TotalCount)
                    of @_result.TotalCount products
                </span>
            }
        </div>

        @* Product grid *@
        @if (_loading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading…</span>
                </div>
            </div>
        }
        else if (_result is null || _result.Items.Count == 0)
        {
            <div class="alert alert-info text-center" role="alert">
                No products found. Try adjusting your filters.
            </div>
        }
        else
        {
            <div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3">
                @foreach (var product in _result.Items)
                {
                    <div class="col">
                        <ProductCard Product="product"
                                     OnProductSelected="HandleProductSelected"
                                     OnAddToCart="HandleAddToCart" />
                    </div>
                }
            </div>

            @* Pagination *@
            @if (TotalPages > 1)
            {
                <nav class="mt-4" aria-label="Product pagination">
                    <ul class="pagination justify-content-center">
                        <li class="page-item @(_currentPage == 1 ? "disabled" : "")">
                            <button class="page-link" @onclick="() => GoToPageAsync(_currentPage - 1)">Previous</button>
                        </li>
                        @foreach (var p in PageNumbers)
                        {
                            <li class="page-item @(p == _currentPage ? "active" : "")">
                                <button class="page-link" @onclick="() => GoToPageAsync(p)">@p</button>
                            </li>
                        }
                        <li class="page-item @(_currentPage == TotalPages ? "disabled" : "")">
                            <button class="page-link" @onclick="() => GoToPageAsync(_currentPage + 1)">Next</button>
                        </li>
                    </ul>
                </nav>
            }
        }
    </section>
</div>

@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    // ── State ──
    private List<string>? _categories;
    private HashSet<string> _selectedCategories = new();
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private const int PageSize = 9;
    private bool _loading = true;
    private string? _errorMessage;
    private PagedResult<Product>? _result;

    private int TotalPages => _result is null || _result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)_result.TotalCount / _result.PageSize);

    private IEnumerable<int> PageNumbers
    {
        get
        {
            int total = TotalPages;
            int start = Math.Max(1, _currentPage - 2);
            int end = Math.Min(total, start + 4);
            start = Math.Max(1, end - 4);
            return Enumerable.Range(start, end - start + 1);
        }
    }

    // ── Lifecycle ──
    protected override async Task OnInitializedAsync()
    {
        await LoadCategoriesAsync();
        await SearchAsync();
    }

    // ── Data loading ──
    private async Task LoadCategoriesAsync()
    {
        try
        {
            _categories = await ProductService.GetCategoriesAsync();
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to load categories: {ex.Message}";
        }
    }

    private async Task SearchAsync()
    {
        _loading = true;
        _errorMessage = null;
        StateHasChanged();

        try
        {
            var filter = new ProductFilter(
                Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
                MinPrice: _minPrice,
                MaxPrice: _maxPrice,
                InStockOnly: _inStockOnly
            );

            _result = await ProductService.SearchAsync(filter, _sortBy, _currentPage, PageSize);
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to load products: {ex.Message}";
            _result = null;
        }
        finally
        {
            _loading = false;
        }
    }

    // ── Filter actions ──
    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private async Task ApplyFiltersAsync()
    {
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task ClearFiltersAsync()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        _currentPage = 1;
        await SearchAsync();
    }

    // ── Sort ──
    private async Task OnSortChangedAsync()
    {
        _currentPage = 1;
        await SearchAsync();
    }

    // ── Pagination ──
    private async Task GoToPageAsync(int page)
    {
        if (page < 1 || page > TotalPages || page == _currentPage)
            return;

        _currentPage = page;
        await SearchAsync();
    }

    // ── Card callbacks ──
    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private async Task HandleAddToCart(Product product)
    {
        await OnAddToCart.InvokeAsync(product);
    }

    // ── Retry ──
    private async Task RetryAsync()
    {
        if (_categories is null)
            await LoadCategoriesAsync();
        await SearchAsync();
    }
}
