@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    // ── State ──
    private List<string>? _categories;
    private HashSet<string> _selectedCategories = new();
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private const int PageSize = 9;
    private bool _loading = true;
    private string? _errorMessage;
    private PagedResult<Product>? _result;

    private int TotalPages => _result is null || _result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)_result.TotalCount / _result.PageSize);

    private IEnumerable<int> PageNumbers
    {
        get
        {
            int total = TotalPages;
            int start = Math.Max(1, _currentPage - 2);
            int end = Math.Min(total, start + 4);
            start = Math.Max(1, end - 4);
            return Enumerable.Range(start, end - start + 1);
        }
    }

    // ── Lifecycle ──
    protected override async Task OnInitializedAsync()
    {
        await LoadCategoriesAsync();
        await SearchAsync();
    }

    // ── Data loading ──
    private async Task LoadCategoriesAsync()
    {
        try
        {
            _categories = await ProductService.GetCategoriesAsync();
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to load categories: {ex.Message}";
        }
    }

    private async Task SearchAsync()
    {
        _loading = true;
        _errorMessage = null;
        StateHasChanged();

        try
        {
            var filter = new ProductFilter(
                Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
                MinPrice: _minPrice,
                MaxPrice: _maxPrice,
                InStockOnly: _inStockOnly
            );

            _result = await ProductService.SearchAsync(filter, _sortBy, _currentPage, PageSize);
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to load products: {ex.Message}";
            _result = null;
        }
        finally
        {
            _loading = false;
        }
    }

    // ── Filter actions ──
    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private async Task ApplyFiltersAsync()
    {
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task ClearFiltersAsync()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        _currentPage = 1;
        await SearchAsync();
    }

    // ── Sort ──
    private async Task OnSortChangedAsync()
    {
        _currentPage = 1;
        await SearchAsync();
    }

    // ── Pagination ──
    private async Task GoToPageAsync(int page)
    {
        if (page < 1 || page > TotalPages || page == _currentPage)
            return;

        _currentPage = page;
        await SearchAsync();
    }

    // ── Card callbacks ──
    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private async Task HandleAddToCart(Product product)
    {
        await OnAddToCart.InvokeAsync(product);
    }

    // ── Retry ──
    private async Task RetryAsync()
    {
        if (_categories is null)
            await LoadCategoriesAsync();
        await SearchAsync();
    }
}

